26	    /// Moves `write` pointer by `count` places forward.
27	    ///
28	    /// # Safety
29	    ///
30	    /// First `count` items in free space must be initialized.
31	    ///
32	    /// Must not be called concurrently.
33	    unsafe fn advance_write_index(&self, count: usize) {
