93	    /// Appends items from slice to the ring buffer.
94	    ///
95	    /// Returns count of items been appended to the ring buffer.
96	    fn push_slice(&mut self, elems: &[Self::Item]) -> usize
97	    where
98	        Self::Item: Copy,
