108	                + if elems.len() < right.len() {
109	                    write_slice(&mut right[..elems.len()], elems);
110	                    elems.len()
111	                } else {
112	                    write_slice(right, &elems[..right.len()]);
113	                    right.len()
114	                }
115	        };
116	        unsafe { self.advance_write_index(count) };
117	        count
118	    }
