77	    ///
78	    /// # Safety
79	    ///
80	    /// Initialized contents of the storage must be properly dropped.
81	    pub unsafe fn into_raw_parts(self) -> (S, usize, usize) {
82	        let this = ManuallyDrop::new(self);
